CREATE TABLE IF NOT EXISTS t_p97754588_arte_deli_site.products (id SERIAL PRIMARY KEY, name VARCHAR(100) NOT NULL, description TEXT, composition TEXT, price INTEGER NOT NULL, category VARCHAR(50) DEFAULT 'pizza', size VARCHAR(20) DEFAULT '32 см', emoji VARCHAR(10) DEFAULT '🍕', image_url TEXT, tags TEXT[] DEFAULT '{}', is_available BOOLEAN DEFAULT TRUE, sort_order INTEGER DEFAULT 0, created_at TIMESTAMPTZ DEFAULT NOW(), updated_at TIMESTAMPTZ DEFAULT NOW())
